     1→'use client';
     2→
     3→import { useState, useRef } from 'react';
     4→import Link from 'next/link';
     5→import { PostData, Heading } from '@/lib/markdown';
     6→import { getPostUrl } from '@/lib/urls';
     7→import { useLanguage } from './LanguageProvider';
     8→import { useSidebarAutoScroll } from '@/hooks/useSidebarAutoScroll';
     9→import { padNumber } from '@/lib/format-utils';
    10→import TocPanel from './TocPanel';
    11→import ShareBar from './ShareBar';
    12→import { siteConfig } from '../../site.config';
    13→
    14→interface PostSidebarProps {
    15→  seriesSlug?: string;
    16→  seriesTitle?: string;
    17→  posts?: PostData[];
    18→  currentSlug: string;
    19→  headings: Heading[];
    20→  localeHeadings?: Record<string, Heading[]>;
    21→  shareUrl?: string;
    22→  shareTitle?: string;
    23→}
    24→
    25→function getVisibleIndices(total: number, current: number): (number | 'ellipsis')[] {
    26→  if (total <= 7) return Array.from({ length: total }, (_, i) => i);
    27→  const result: (number | 'ellipsis')[] = [];
    28→  result.push(0);
    29→  const windowStart = Math.max(1, current - 2);
    30→  const windowEnd = Math.min(total - 2, current + 2);
    31→  if (windowStart > 1) result.push('ellipsis');
    32→  for (let i = windowStart; i <= windowEnd; i++) result.push(i);
    33→  if (windowEnd < total - 2) result.push('ellipsis');
    34→  result.push(total - 1);
    35→  return result;
    36→}
    37→
    38→export default function PostSidebar({ seriesSlug, seriesTitle, posts, currentSlug, headings, localeHeadings, shareUrl, shareTitle }: PostSidebarProps) {
    39→  const { t, language } = useLanguage();
    40→  const activeHeadings = localeHeadings?.[language] ?? headings;
    41→  const hasSeries = !!(seriesSlug && posts && posts.length > 0);
    42→  const currentIndex = hasSeries ? posts!.findIndex(p => p.slug === currentSlug) : -1;
    43→  // Chronological sort (ascending date) — used for both progress counter and isPast styling
    44→  const sortedPosts = hasSeries
    45→    ? [...posts!].sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime())
    46→    : null;
    47→  const progressIndex = hasSeries ? sortedPosts!.findIndex(p => p.slug === currentSlug) : -1;
    48→  const currentItemRef = useRef<HTMLLIElement>(null);
    49→  const sidebarRef = useRef<HTMLElement>(null);
    50→  const [seriesCollapsed, setSeriesCollapsed] = useState(false);
    51→  useSidebarAutoScroll(sidebarRef, currentItemRef, currentSlug);
    52→
    53→  return (
    54→    <aside
    55→      ref={sidebarRef}
    56→      className="hidden lg:block sticky top-20 self-start w-[280px] max-h-[calc(100vh-6rem)] overflow-y-auto pr-4 scrollbar-hide hover:scrollbar-thin"
    57→    >
    58→      {/* TOC — always at top */}
    59→      <TocPanel
    60→        headings={activeHeadings}
    61→        className={`mb-6 ${hasSeries ? 'pb-4 border-b border-muted/10' : ''}`}
    62→      />
    63→
    64→      {/* Series section — below TOC */}
    65→      {hasSeries && (
    66→        <div>
    67→          {/* Header — always visible */}
    68→          <div className="mb-3">
    69→            <div className="flex items-center justify-between mb-1">
    70→              <span className="text-[10px] font-sans font-bold uppercase tracking-widest text-accent">
    71→                {t('series')}
    72→              </span>
    73→              <span className="text-[10px] font-mono text-muted/60">
    74→                {progressIndex >= 0 ? progressIndex + 1 : '?'} / {posts!.length}
    75→              </span>
    76→            </div>
    77→            <div className="flex items-start justify-between gap-2">
    78→              <Link href={`/series/${seriesSlug}`} className="group block no-underline flex-1 min-w-0">
    79→                <h3 className="font-serif font-bold text-heading text-base leading-snug group-hover:text-accent transition-colors">
    80→                  {seriesTitle}
    81→                </h3>
    82→              </Link>
    83→              <button
    84→                onClick={() => setSeriesCollapsed(prev => !prev)}
    85→                className="flex-shrink-0 mt-0.5 text-muted hover:text-foreground transition-colors"
    86→                aria-label={seriesCollapsed ? 'Expand series' : 'Collapse series'}
    87→              >
    88→                <svg
    89→                  className={`w-3.5 h-3.5 transition-transform duration-200 ${seriesCollapsed ? '' : 'rotate-180'}`}
    90→                  fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}
    91→                >
    92→                  <path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" />
    93→                </svg>
    94→              </button>
    95→            </div>
    96→          </div>
    97→
    98→          {/* Collapsible: post list + footer link */}
    99→          {!seriesCollapsed && (
   100→            <>
   101→              <nav aria-label="Series navigation" className="mb-4 animate-slide-down">
   102→                <ul className="space-y-1 relative before:absolute before:left-[11px] before:top-3 before:bottom-3 before:w-px before:bg-muted/15">
   103→                  {getVisibleIndices(posts!.length, currentIndex).map((item, i) => {
   104→                    if (item === 'ellipsis') {
   105→                      return (
   106→                        <li key={`ellipsis-${i}`} className="flex items-center py-1 pl-3">
   107→                          <span className="text-xs font-mono text-muted/40 tracking-widest">···</span>
   108→                        </li>
   109→                      );
   110→                    }
   111→                    const post = posts![item];
   112→                    const isCurrent = post.slug === currentSlug;
   113→                    const chronoIndex = sortedPosts ? sortedPosts.findIndex(p => p.slug === post.slug) : item;
   114→                    const isPast = chronoIndex < progressIndex;
   115→
   116→                    return (
   117→                      <li key={post.slug} ref={isCurrent ? currentItemRef : undefined} className="relative">
   118→                        <Link
   119→                          href={getPostUrl(post)}
   120→                          className={`group flex items-start gap-3 py-2 px-2 -mx-2 rounded-lg no-underline transition-all duration-200 ${
   121→                            isCurrent ? 'bg-accent/5' : 'hover:bg-muted/5'
   122→                          }`}
   123→                          aria-current={isCurrent ? 'page' : undefined}
   124→                        >
   125→                          <div className={`relative z-10 flex-shrink-0 w-6 h-6 rounded-full flex items-center justify-center text-[10px] font-mono font-bold transition-colors ${
   126→                            isCurrent
   127→                              ? 'bg-accent text-white shadow-sm shadow-accent/30'
   128→                              : isPast
   129→                                ? 'bg-accent/20 text-accent'
   130→                                : 'bg-muted/10 text-muted group-hover:bg-muted/20 group-hover:text-foreground'
   131→                          }`}>
   132→                            {padNumber(item + 1)}
   133→                          </div>
   134→                          <div className="flex-1 min-w-0 pt-0.5">
   135→                            <span className={`block text-sm leading-snug transition-colors ${
   136→                              isCurrent
   137→                                ? 'text-accent font-semibold'
   138→                                : isPast
   139→                                  ? 'text-foreground/70 group-hover:text-foreground'
   140→                                  : 'text-muted group-hover:text-foreground'
   141→                            }`}>
   142→                              {post.title}
   143→                            </span>
   144→                          </div>
   145→                        </Link>
   146→                      </li>
   147→                    );
   148→                  })}
   149→                </ul>
   150→              </nav>
   151→
   152→              <Link
   153→                href={`/series/${seriesSlug}`}
   154→                className="text-xs font-sans text-muted hover:text-accent transition-colors no-underline flex items-center gap-1"
   155→              >
